#!/usr/bin/env Rscript

################################################################################
# Module 2: Persistent homology analysis
#
# Purpose:
#   Run Ripser++ on phenotype-specific numeric filtration matrices generated by
#   Module 1 and parse Ripser++ text outputs into standardized barcode tables.
#
# Expected input from Module 1:
#   <prefix>_module2_ripser_input_list.txt
#   Each non-empty, non-comment line contains one numeric matrix path.
#   Numeric matrices should be square, tab-delimited, and contain no row/column names.
#
# Main outputs:
#   1) Raw Ripser++ output text files
#   2) Parsed barcode tables for each input matrix
#   3) A combined barcode table across all phenotype/network matrices
#   4) Per-network homology summary table
#   5) Module 3 input manifest
#   6) Run manifest recording commands, exit codes, and output paths
#   7) Overlaid H0 and H1 topological-index plots (PNG and/or PDF)
#   8) Plot manifest recording dimension-specific figure paths
#
# Design principles:
#   - no hard-coded paths
#   - single input list from Module 1
#   - consistent output naming and table schemas
#   - explicit validation and informative error messages
#   - parses PH output once so downstream modules do not repeat parser logic
################################################################################

options(stringsAsFactors = FALSE)

##### 1. Lightweight command-line parser ######################################

parse_args <- function(argv) {
  args <- list()
  i <- 1
  while (i <= length(argv)) {
    key <- argv[[i]]
    if (!startsWith(key, "--")) {
      stop("Unexpected argument: ", key, "\nArguments must use --key value format.", call. = FALSE)
    }
    key <- sub("^--", "", key)
    if (i == length(argv) || startsWith(argv[[i + 1]], "--")) {
      args[[key]] <- TRUE
      i <- i + 1
    } else {
      args[[key]] <- argv[[i + 1]]
      i <- i + 2
    }
  }
  args
}

get_arg <- function(args, name, default = NULL, required = FALSE) {
  value <- args[[name]]
  if (is.null(value)) {
    if (required) stop("Missing required argument: --", name, call. = FALSE)
    return(default)
  }
  value
}

as_logical_arg <- function(x) {
  if (is.logical(x)) return(x)
  x <- tolower(as.character(x))
  if (x %in% c("true", "t", "1", "yes", "y")) return(TRUE)
  if (x %in% c("false", "f", "0", "no", "n")) return(FALSE)
  stop("Cannot parse logical value: ", x, call. = FALSE)
}

